import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation மற்றும் Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Safety/image-moderation-and-access-mode.md","filePath":"ta/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),r={name:"ta/Safety/image-moderation-and-access-mode.md"};function o(s,e,n,c,m,p){return t(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="image-moderation-மற்றும்-access-mode" tabindex="-1">Image Moderation மற்றும் Access Mode <a class="header-anchor" href="#image-moderation-மற்றும்-access-mode" aria-label="Permalink to &quot;Image Moderation மற்றும் Access Mode&quot;">​</a></h1><p>Image moderation uploaded images-க்கு age ratings கொடுக்கும். Access mode public access வழியாக எந்த ratings தெரியும் என்பதை கட்டுப்படுத்தும்.</p><p>இது public gallery, public file URLs, random image API ஆகியவற்றை பாதிக்கும். admin panel-ஐ இது கட்டுப்படுத்தாது. Administrators எல்லா files-ஐயும் பார்க்கவும் manage செய்யவும் முடியும்.</p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>admin panel திறந்து செல்லவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>main settings:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-என்ன-செய்கிறது" tabindex="-1">Access Mode என்ன செய்கிறது <a class="header-anchor" href="#access-mode-என்ன-செய்கிறது" aria-label="Permalink to &quot;Access Mode என்ன செய்கிறது&quot;">​</a></h2><p>Access mode எந்த age ratings public-ஆக காட்டலாம் என்பதை முடிவு செய்கிறது.</p><p>தற்போதைய modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>General மட்டும்</td></tr></tbody></table><p>default Adult mode.</p><p>private sites அல்லது mature content உள்ள sites-க்கு Adult mode பொருத்தமாக இருக்கலாம். public gallery பாதுகாப்பாக இருக்க வேண்டும் என்றால் Youth, Teen, அல்லது Child mode தேர்வு செய்யவும்.</p><h2 id="moderation-enable-செய்தால்-என்ன-ஆகும்" tabindex="-1">Moderation Enable செய்தால் என்ன ஆகும் <a class="header-anchor" href="#moderation-enable-செய்தால்-என்ன-ஆகும்" aria-label="Permalink to &quot;Moderation Enable செய்தால் என்ன ஆகும்&quot;">​</a></h2><p>moderation enabled என்றால் upload நேரத்தில் ImgBed selected moderation provider-ஐ call செய்து detected age rating சேமிக்கும்.</p><p>main ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>பாதுகாப்பான public content</td></tr><tr><td>R12</td><td>லேசான sensitive content</td></tr><tr><td>R16</td><td>நடுத்தர sensitive content</td></tr><tr><td>R18</td><td>adult content</td></tr></tbody></table><p>public access முடிவு செய்யும் போது moderation result பயன்படுத்தப்படும்.</p><p>moderation enabled இல்லாவிட்டால், அல்லது old files-க்கு rating இல்லாவிட்டால், அவை unrated ஆக கருதப்படும். rating இல்லாததால் மட்டும் unrated files public gallery அல்லது random image API-இல் இருந்து தானாக remove ஆகாது.</p><h2 id="moderation-provider-தேர்வு" tabindex="-1">Moderation Provider தேர்வு <a class="header-anchor" href="#moderation-provider-தேர்வு" aria-label="Permalink to &quot;Moderation Provider தேர்வு&quot;">​</a></h2><p>available providers:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>ஒவ்வொரு provider-க்கும் requirements வேறு:</p><ul><li>moderatecontent.com பொதுவாக API Key தேவை.</li><li>nsfwjs பொதுவாக API endpoint URL தேவை.</li><li>Sightengine-க்கு API user மற்றும் API secret தேவை.</li></ul><p>உங்கள் account, availability, detection quality அடிப்படையில் provider தேர்வு செய்யவும். moderation enabled மற்றும் சரியாக configured என்றால் ImgBed upload நேரத்தில் image rating எழுத முயலும்.</p><h2 id="public-gallery-மீது-effect" tabindex="-1">Public Gallery மீது Effect <a class="header-anchor" href="#public-gallery-மீது-effect" aria-label="Permalink to &quot;Public Gallery மீது Effect&quot;">​</a></h2><p>public gallery access mode படி files filter செய்யும்.</p><p>உதாரணங்கள்:</p><ul><li>Adult mode: R18 images தோன்றலாம்.</li><li>Youth mode: R18 images மறைக்கப்படும்.</li><li>Teen mode: R16 மற்றும் R18 images மறைக்கப்படும்.</li><li>Child mode: General images மட்டும் காட்டப்படும்.</li></ul><p>இது normal public access-ஐ மட்டுமே பாதிக்கும். admin panel எல்லா files-ஐயும் காட்டும்.</p><h2 id="public-file-urls-மீது-effect" tabindex="-1">Public File URLs மீது Effect <a class="header-anchor" href="#public-file-urls-மீது-effect" aria-label="Permalink to &quot;Public File URLs மீது Effect&quot;">​</a></h2><p>Public file URLs visitors திறக்கும் direct image links.</p><p>file rating current access mode-ல் allowed என்றால் ImgBed original image தரும்.</p><p>rating allowed level-ஐ விட மேலாக இருந்தால் normal public access original image தராது. அதற்கு பதில் configured blocked result அல்லது மாற்று blocked image தரப்படும்.</p><p>உதாரணம்:</p><ul><li>current mode Child mode.</li><li>image R18 rated.</li><li>visitor public URL directly திறக்கிறார்.</li><li>ImgBed அந்த visitor-க்கு R18 original image தராது.</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>admin panel-ல் files பார்க்கும் administrators இந்த restriction-ல் பாதிக்கப்படமாட்டார்கள்.</p><h2 id="random-image-api-மீது-effect" tabindex="-1">Random Image API மீது Effect <a class="header-anchor" href="#random-image-api-மீது-effect" aria-label="Permalink to &quot;Random Image API மீது Effect&quot;">​</a></h2><p>random image API candidate pool-ஐ access mode அடிப்படையில் filter செய்கிறது.</p><p>Child mode-ல் random images General-rated files-ல் இருந்து மட்டுமே தேர்வு செய்யப்படும்.</p><p>Youth mode-ல் General, R12, R16 files வரலாம்; R18 வராது.</p><p>இதனால் random image API public gallery restrictions-ஐ bypass செய்ய முடியாது.</p><h2 id="list-rules-உடன்-தொடர்பு" tabindex="-1">List Rules உடன் தொடர்பு <a class="header-anchor" href="#list-rules-உடன்-தொடர்பு" aria-label="Permalink to &quot;List Rules உடன் தொடர்பு&quot;">​</a></h2><p>Access mode மட்டுமே public access rule அல்ல. இது allow/block list rules உடன் சேர்ந்து இயங்கும்.</p><p>சுருக்கமாக:</p><ul><li>Allowlisted content முதலில் public ஆகும்.</li><li>Blocklisted content regular visitors-க்கு directly தெரியாது.</li><li>எந்த list-யிலும் இல்லாத content பின்னர் access mode அடிப்படையில் check செய்யப்படும்.</li></ul><p>ஒரு image age rating மற்றும் list rules இரண்டாலும் restricted என்றால் regular visitors original file-ஐ directly பார்க்க முடியாது.</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Public sites:</p><ul><li>moderation enable செய்யவும்.</li><li>site audience-க்கு பொருந்தும் access mode தேர்வு செய்யவும்.</li><li>all-age visitors-க்கு Child mode அல்லது Teen mode பயன்படுத்தவும்.</li><li>mature content public காட்ட வேண்டாம் என்றால் Adult mode தவிர்க்கவும்.</li><li>admin panel-ல் file ratings review செய்து தேவைப்பட்டால் manually adjust செய்யவும்.</li></ul><p>Private அல்லது personal sites:</p><ul><li>Adult mode பொதுவாக fine.</li><li>பயனுள்ளதாக இருந்தால் moderation enable செய்யவும்.</li><li>admin panel-ல் ratings review/adjust செய்யவும்.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="access-mode-மாற்றினால்-files-admin-panel-ல்-மறையுமா" tabindex="-1">Access Mode மாற்றினால் Files Admin Panel-ல் மறையுமா? <a class="header-anchor" href="#access-mode-மாற்றினால்-files-admin-panel-ல்-மறையுமா" aria-label="Permalink to &quot;Access Mode மாற்றினால் Files Admin Panel-ல் மறையுமா?&quot;">​</a></h3><p>இல்லை.</p><p>Access mode normal public access-ஐ மட்டும் பாதிக்கும். admin panel பாதிக்கப்படாது.</p><h3 id="child-mode-க்கு-மாற்றிய-பிறகு-public-gallery-ல்-images-குறைந்தது-ஏன்" tabindex="-1">Child Mode-க்கு மாற்றிய பிறகு Public Gallery-ல் Images குறைந்தது ஏன்? <a class="header-anchor" href="#child-mode-க்கு-மாற்றிய-பிறகு-public-gallery-ல்-images-குறைந்தது-ஏன்" aria-label="Permalink to &quot;Child Mode-க்கு மாற்றிய பிறகு Public Gallery-ல் Images குறைந்தது ஏன்?&quot;">​</a></h3><p>Child mode General-rated files மட்டும் public காட்டும். R12, R16, R18 files filter ஆகும்.</p><h3 id="public-urls-adult-images-திறக்குமா" tabindex="-1">Public URLs Adult Images திறக்குமா? <a class="header-anchor" href="#public-urls-adult-images-திறக்குமா" aria-label="Permalink to &quot;Public URLs Adult Images திறக்குமா?&quot;">​</a></h3><p>current access mode அந்த rating-ஐ allow செய்யவில்லை என்றால் normal public URLs original image தராது.</p><h3 id="random-image-api-restricted-images-தருமா" tabindex="-1">Random Image API Restricted Images தருமா? <a class="header-anchor" href="#random-image-api-restricted-images-தருமா" aria-label="Permalink to &quot;Random Image API Restricted Images தருமா?&quot;">​</a></h3><p>இல்லை.</p><p>random image API candidates current access mode படி filter செய்யும்.</p><h3 id="பழைய-unrated-images-என்ன-ஆகும்" tabindex="-1">பழைய Unrated Images என்ன ஆகும்? <a class="header-anchor" href="#பழைய-unrated-images-என்ன-ஆகும்" aria-label="Permalink to &quot;பழைய Unrated Images என்ன ஆகும்?&quot;">​</a></h3><p>moderation results இல்லாததால் மட்டும் unrated images தானாக hidden ஆகாது. பின்னர் admin panel-ல் ratings adjust செய்யலாம்.</p>',67)])])}const b=i(r,[["render",o]]);export{h as __pageData,b as default};
